#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create a buffer_adaptor for the given buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Check available space using buffer_adaptor
    // Calculate required space: sizeof(header) + (number of items × sizeof(uint32_t))
    size_t required_space = sizeof(header) + (items.size() * sizeof(uint32_t));

    // Get the write pointer from buffer_adaptor
    uint8_t* write_ptr = adaptor.write_ptr();

    // Check if there's enough space in the buffer
    if (write_ptr + required_space > buffer.data() + buffer.size()) {
        return false; // Insufficient space
    }

    // Create a binary_stream with the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Write the header using put
    stream.put(header);

    // Write the container data using write_container
    stream.write_container(items);

    return true; // Write successful
}
