    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Read the uint32_t header using the binary_stream's operator>>
    uint32_t header;
    stream >> header;

    // Read the null-terminated string using the binary_stream's view method
    std::string_view message = stream.view();

    // Return a MessagePacket containing the header and the string_view
    return MessagePacket{header, message};
}

