struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create buffer_read_adaptor object from input buffer
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    Header header;

    // Use copy() to peek at header data without advancing read cursor
    adaptor.copy(&header);

    // Use read_ptr() to verify pointer position
    const uint8_t* current_ptr = adaptor.read_ptr();
    assert(current_ptr == buffer.data() && "Read pointer should point to buffer start");

    // Verify the copied data matches the original buffer
    const uint8_t* header_ptr = reinterpret_cast<const uint8_t*>(&header);
    for (size_t i = 0; i < sizeof(Header); ++i) {
        assert(header_ptr[i] == buffer[i] && "Copied header should match original buffer");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create buffer_read_adaptor object from input buffer
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    // Peek at first byte using copy()
    uint8_t first_byte;
    adaptor.copy(&first_byte);

    // Conditionally read based on peeked value
    if (first_byte == 0x01) { // Example condition: first byte equals 0x01
        // Read entire buffer using read()
        std::vector<uint8_t> result(buffer.size());
        adaptor.read(result.data(), result.size());

        // Verify the read data matches the original buffer
        for (size_t i = 0; i < buffer.size(); ++i) {
            assert(result[i] == buffer[i] && "Read data should match original buffer");
        }

        return result;
    } else {
