        adaptor.write(sensor_id);  // Write sensor_id directly

        for (auto temp : temperatures) {
            // Convert temperature from native to little-endian using runtime parameters
            float converted_temp = hexi::endian::conditional_reverse(temp, 
                                                                   std::endian::native, 
                                                                   std::endian::little);
            adaptor.write(converted_temp);
        }

        // Convert pressure from native to little-endian using runtime parameters
        double converted_pressure = hexi::endian::conditional_reverse(pressure, 
                                                                    std::endian::native, 
                                                                    std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read fields with endian conversion
        adaptor.read(sensor_id);  // Read sensor_id directly

        // Read all temperatures
        for (auto& temp : temperatures) {
            float read_temp;
            adaptor.read(read_temp);
            // Convert from little-endian to native using in-place conversion
            hexi::endian::little_to_native_inplace(read_temp);
            temp = read_temp;
        }

        // Read pressure
        double read_pressure;
        adaptor.read(read_pressure);
        // Convert from little-endian to native using in-place conversion
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
    }
};

